refsection.programlisting:
fixed = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
fixed = imresize(fixed, [120 160]);
moving = imtranslate(fixed, [5 3]);
[registered, transform] = imregister(moving, fixed, "phasecorr");
disp(transform);
subplot(1, 3, 1);
imshow(fixed);
subplot(1, 3, 2);
imshow(moving);
subplot(1, 3, 3);
imshow(registered);
